import{_ as o,o as r,c as t,a0 as l}from"./chunks/framework.tsJrOMu2.js";const m=JSON.parse('{"title":"Telegram 与服务器风控的血与泪","description":"","frontmatter":{"title":"Telegram 与服务器风控的血与泪","date":"2026-03-29T00:00:00.000Z"},"headers":[],"relativePath":"tools/risk-control.md","filePath":"tools/risk-control.md"}'),a={name:"tools/risk-control.md"};function n(s,e,i,g,d,c){return r(),t("div",null,[...e[0]||(e[0]=[l('<h1 id="telegram-与服务器风控的血与泪" tabindex="-1">Telegram 与服务器风控的血与泪 <a class="header-anchor" href="#telegram-与服务器风控的血与泪" aria-label="Permalink to &quot;Telegram 与服务器风控的血与泪&quot;">​</a></h1><p>在折腾各种 VPS 和社交平台的自动机器人的时候，封号风控是我们遇到最大的拦路虎。这一篇专门讲讲被封和解封的坑。</p><h2 id="_1-telegram-注册即死-秒封号" tabindex="-1">1. Telegram 注册即死（秒封号） <a class="header-anchor" href="#_1-telegram-注册即死-秒封号" aria-label="Permalink to &quot;1. Telegram 注册即死（秒封号）&quot;">​</a></h2><p><strong>场景还原</strong>： 想用国内手机号注册一个 Telegram 小号用来挂机测试，刚收到验证码填进去，页面一转，账号被提示 <code>Your phone number is banned</code>。</p><p><strong>排查过程</strong>： 这通常有两个原因：</p><ul><li>注册 IP 环境被污染（常见的机场梯子节点被大量滥用，IP 在黑名单）。</li><li>号段本身被重点关照。国内号码注册，默认就会被系统高度风控。</li></ul><p><strong>避坑与解封指南</strong>：</p><ul><li><strong>注册新号，尽量购买独立原生 IP 的 VPS 自建节点</strong>，或者使用家宽环境，千万不要用万人骑的机场代理去注册。</li><li><strong>解封路径</strong>：别慌。用邮箱直接发送申诉邮件给 <code>recover@telegram.org</code>。 <ul><li><strong>邮件标题</strong>：<code>Please unban my account</code></li><li><strong>正文</strong>：写清楚你的完整手机号（一定要带 <code>+86</code> 国家区号），表明自己是个正常的用户（&quot;I am a normal user...&quot;），不是发垃圾广告的机器。通常几天后就会自动解封。</li></ul></li><li><strong>刚解封的新号</strong>：别立刻跑去私信陌生人，别疯狂加几千人的大群，最好先养号 3 天。</li></ul><h2 id="_2-网站备案与服务器拉黑-神秘的-403-拦截页" tabindex="-1">2. 网站备案与服务器拉黑：神秘的 403 / 拦截页 <a class="header-anchor" href="#_2-网站备案与服务器拉黑-神秘的-403-拦截页" aria-label="Permalink to &quot;2. 网站备案与服务器拉黑：神秘的 403 / 拦截页&quot;">​</a></h2><p><strong>场景还原</strong>： 把个人建站的 Web 服务跑在了国内云服务器（比如阿里云、腾讯云等），自己测试的时候可以通过 IP 加端口正常访问。 然后高高兴兴地去域名服务商那里买了域名，刚解析到这个 IP，用浏览器一打开，立刻变成了一个大大的提示页：“该网站未备案...阻断访问”。</p><p><strong>排查过程</strong>： 国内服务商对 HTTP 流量查得很严，凡是挂载在 80/443 端口的域名请求，只要检测出未备案的 host 头，机房的防火墙就会立刻拦截。</p><p><strong>避坑指南</strong>： 如果你仅仅是自己折腾、或者搭建小范围的工具站，不想走长达两三周的备案流程：</p><ul><li><strong>方案A</strong>：将服务器换到海外节点（如香港、新加坡或美国）。</li><li><strong>方案B</strong>：如果你非要用国内服务器，那就在 Cloudflare 上搭建内网穿透隧道（Cloudflare Tunnel，即 <code>cloudflared</code>），让 Cloudflare 直接把国外的请求转发给你内网服务器的任意端口，完美绕过国内云服务商的域名白名单阻断。这招对于不想暴露服务器真实 IP 防 DDoS 也非常好用。</li></ul>',13)])])}const p=o(a,[["render",n]]);export{m as __pageData,p as default};
